    pub fn validate(&self) -> Result<()> {
        // Validate upper bound for num_lines
        if self.num_lines > MAX_LINES {
            anyhow::bail!(
                "Number of lines ({}) exceeds maximum allowed ({})",
                self.num_lines,
                MAX_LINES
            );
        }

        // Validate file path is not empty
        if self.file.as_os_str().is_empty() {
            anyhow::bail!("File path cannot be empty");
        }

        Ok(())
    }
