/// Read and return the last N lines from a file efficiently
///
/// This function uses a buffer-based approach to read from the end of the file,
/// which is memory-efficient for large files.
///
/// # Arguments
///
/// * `file_path` - Path to the file to read
/// * `num_lines` - Number of lines to retrieve from the end
///
/// # Returns
///
/// A vector of strings, each representing one of the last N lines
///
/// # Errors
///
/// Returns an error if the file cannot be opened or read
fn read_last_n_lines(file_path: &PathBuf, num_lines: usize) -> Result<Vec<String>> {
    // Handle edge case: if num_lines is 0, return empty vector
    if num_lines == 0 {
        return Ok(Vec::new());
    }

    let mut file = File::open(file_path)
        .with_context(|| format!("Failed to open file '{}'", file_path.display()))?;

    // Get file size
    let file_size = file.metadata()
        .with_context(|| format!("Failed to get metadata for '{}'", file_path.display()))?
        .len();

    // Handle edge case: empty file
    if file_size == 0 {
        return Ok(Vec::new());
    }

    // For small files, just read everything
    if file_size <= BUFFER_SIZE as u64 {
        file.seek(SeekFrom::Start(0))?;
        let reader = BufReader::new(file);
        let all_lines: Vec<String> = reader.lines().collect::<Result<Vec<_>, _>>()?;

        // Return last N lines (or all lines if file has fewer than N)
        let start_index = all_lines.len().saturating_sub(num_lines);
        return Ok(all_lines[start_index..].to_vec());
    }

    // For larger files, read from the end
    let mut lines = Vec::new();
    let mut buffer = vec![0u8; BUFFER_SIZE];
    let mut position = file_size;
    let mut remaining_content = Vec::new();

    loop {
        // Calculate how much to read (either BUFFER_SIZE or remaining bytes)
        let read_size = std::cmp::min(BUFFER_SIZE as u64, position) as usize;
        position -= read_size as u64;

        // Seek to the position and read
        file.seek(SeekFrom::Start(position))?;
        std::io::Read::read_exact(&mut file, &mut buffer[..read_size])?;

        // Prepend to remaining content
        let mut combined = buffer[..read_size].to_vec();
        combined.append(&mut remaining_content);
        remaining_content = combined;

        // Count newlines in the buffer
        let newline_count = remaining_content.iter().filter(|&&b| b == b'\n').count();

        // If we have enough lines or we've read the entire file, process the content
        if newline_count >= num_lines || position == 0 {
            // Convert bytes to string
            let content = String::from_utf8_lossy(&remaining_content).to_string();

            // Split into lines
            let all_lines: Vec<&str> = content.lines().collect();

            // Handle the case where the file doesn't end with a newline
            // If we've read the whole file and there's content after the last newline,
            // we need to include it
            let mut result_lines = all_lines.clone();

            // If the content doesn't end with a newline but has content after the last newline
            if !remaining_content.is_empty() && remaining_content[remaining_content.len() - 1] != b'\n' {
                // The lines are already correctly split
            }

            // Get the last N lines
            let start_index = result_lines.len().saturating_sub(num_lines);
            lines = result_lines[start_index..].iter().map(|s| s.to_string()).collect();

            break;
        }

        // If we've reached the beginning of the file, stop
        if position == 0 {
            break;
        }
    }

    Ok(lines)
}

fn main() -> Result<()> {
