/// Read the last N lines from a file efficiently
///
/// This function uses a buffer-based approach to read from the end of the file:
/// - For small files (<=8KB), reads the entire file
/// - For larger files, reads backwards in chunks until N lines are found
///
/// # Arguments
/// * `path` - Path to the file to read
/// * `n` - Number of lines to read from the end
///
/// # Returns
/// A vector of strings containing the last N lines (or fewer if file has fewer lines)
fn read_last_n_lines(path: &PathBuf, n: usize) -> Result<Vec<String>> {
    // Special case: if n is 0, return empty vector
    if n == 0 {
        return Ok(Vec::new());
    }

    let mut file = File::open(path)
        .with_context(|| format!("Failed to open file '{}': file does not exist or cannot be accessed", path.display()))?;

    // Get file size
    let file_size = file.metadata()
        .with_context(|| format!("Failed to read metadata for '{}'", path.display()))?
        .len();

    // Special case: empty file
    if file_size == 0 {
        return Ok(Vec::new());
    }

    // For small files, just read the whole thing
    if file_size <= BUFFER_SIZE as u64 {
        let reader = BufReader::new(file);
        let all_lines: Vec<String> = reader
            .lines()
            .collect::<std::io::Result<Vec<String>>>()
            .with_context(|| format!("Failed to read lines from '{}'", path.display()))?;

        // Return the last N lines (or all if file has fewer than N lines)
        let start_index = all_lines.len().saturating_sub(n);
        return Ok(all_lines[start_index..].to_vec());
    }

    // For larger files, read backwards in chunks
    let mut buffer = vec![0u8; BUFFER_SIZE];
    let mut all_content = Vec::new();
    let mut pos = file_size;
    let mut line_count = 0;

    // Read backwards until we have enough lines
    while pos > 0 && line_count < n {
        let chunk_size = std::cmp::min(BUFFER_SIZE as u64, pos);
        pos = pos.saturating_sub(chunk_size);

        file.seek(SeekFrom::Start(pos))
            .with_context(|| format!("Failed to seek in file '{}'", path.display()))?;

        file.read_exact(&mut buffer[..chunk_size as usize])
            .with_context(|| format!("Failed to read from file '{}'", path.display()))?;

        // Prepend this chunk to our content
        all_content.splice(0..0, buffer[..chunk_size as usize].iter().cloned());

        // Count newlines in accumulated content
        line_count = all_content.iter().filter(|&&b| b == b'\n').count();
    }

    // Convert bytes to string and split into lines
    let content = String::from_utf8_lossy(&all_content).to_string();
    let lines: Vec<String> = content.lines().map(|s| s.to_string()).collect();

    // Return the last N lines
    let start_index = lines.len().saturating_sub(n);
    Ok(lines[start_index..].to_vec())
}

